{
  "summary": "This paper proposes using document similarity methods to automatically create noisy parallel datasets for supervised code translation, addressing the scarcity of parallel corpora. Experiments show that Word Movers Distance effectively identifies similar code pairs, and models trained on these noisy datasets maintain strong performance across multiple language pairs, demonstrating noise tolerance and scalability.",
  "strengths": [
    {
      "point": "Novel approach to alleviate parallel data scarcity using document similarity.",
      "evidence": "The paper introduces a method to create noisy parallel datasets by pairing code documents based on similarity metrics such as TF-IDF, Okapi-BM25, LDA, LSI, and WMD."
    },
    {
      "point": "Empirical demonstration of noise tolerance in code translation models.",
      "evidence": "Experiments show models trained on noisy datasets degrade gradually with noise, with only about 1 percentage point drop at ~90% match accuracy and significant gains over random baselines even at ~47% accuracy."
    },
    {
      "point": "Extension and evaluation across multiple programming languages.",
      "evidence": "The approach is applied to create datasets and train models for 10 language pairs, including less studied ones, showing practical utility and scalability."
    },
    {
      "point": "Comprehensive evaluation with multiple similarity metrics, models, and datasets.",
      "evidence": "The paper evaluates five document similarity methods, three pretrained models (CodeBERT, GraphCodeBERT, PLBART), and uses both ground-truth parallel datasets and large-scale CodeNet data."
    },
    {
      "point": "Resource contribution to the community.",
      "evidence": "Source code and a subset of noisy parallel datasets are provided to facilitate reproducibility and further research."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to recent unsupervised and hybrid code translation methods.",
      "evidence": "The paper omits discussion or empirical comparison to back-translation methods like CodeT5 or unsupervised neural machine translation adaptations, limiting understanding of relative novelty."
    },
    {
      "point": "Lack of principled selection and sensitivity analysis of similarity threshold (δ).",
      "evidence": "No ablation or tuning strategy for δ is provided, nor is it clear how multiple similar documents or ties are handled, affecting dataset quality."
    },
    {
      "point": "Missing detailed ablation on components of document similarity metrics and code granularity.",
      "evidence": "The impact of embedding choices, preprocessing steps, and code snippet granularity on similarity performance is not explored."
    },
    {
      "point": "Evaluation lacks strong supervised and semi-supervised baselines on noisy data.",
      "evidence": "No comparisons to supervised models trained on smaller clean datasets or semi-supervised approaches, nor to transfer learning baselines, are included."
    },
    {
      "point": "Reliance on surface-level metrics without semantic or human evaluation.",
      "evidence": "Metrics like BLEU and CodeBLEU assess syntactic similarity; semantic correctness beyond unit tests and human assessments are missing."
    },
    {
      "point": "Limited characterization of noise types and their differential impact.",
      "evidence": "Noise injection experiments vary quantity but do not analyze noise quality or types such as semantic mismatches or syntactic errors."
    },
    {
      "point": "Insufficient reproducibility details on code preprocessing, tokenization, and vocabulary construction.",
      "evidence": "No information on handling comments, whitespace, identifier splitting, or vocabulary construction is provided."
    },
    {
      "point": "Missing hyperparameter and training protocol details for fine-tuning.",
      "evidence": "Learning rates, batch sizes, epochs, optimizer settings, hardware, random seeds, and variance/error bars are not reported."
    },
    {
      "point": "Ambiguity in definition and use of 'pseudo-match accuracy' on CodeNet dataset.",
      "evidence": "The metric is not clearly defined, and limitations of using problem IDs as proxies for parallelism are not discussed."
    },
    {
      "point": "Lack of intuitive or theoretical explanation for WMD’s superior performance.",
      "evidence": "No discussion on why WMD outperforms simpler methods or how it captures code similarity beyond token overlap."
    },
    {
      "point": "No discussion of scalability and computational cost of WMD on large datasets.",
      "evidence": "Runtime, memory requirements, and potential approximate methods for WMD are not addressed."
    },
    {
      "point": "Potential bias toward language pairs with similar syntax or vocabulary not addressed.",
      "evidence": "No analysis of performance variation across language pairs with differing similarity or tokenization effects."
    },
    {
      "point": "Generalisability limited to imperative/object-oriented languages without cross-domain or cross-project evaluation.",
      "evidence": "No experiments on functional or domain-specific languages, nor on domain adaptation or robustness to domain shifts."
    },
    {
      "point": "Unclear handling of code comments, non-code text, and formatting in similarity computations.",
      "evidence": "No clarification on whether comments or formatting are included or excluded, which affects similarity and noise."
    },
    {
      "point": "Absence of qualitative or quantitative error analysis on translated outputs.",
      "evidence": "No analysis of error types or common mistakes made by models trained on noisy data."
    },
    {
      "point": "No discussion of ethical or security implications of noisy code translation.",
      "evidence": "Potential risks of generating incorrect or insecure code due to noise are not considered."
    },
    {
      "point": "Lack of analysis on dataset biases and representativeness.",
      "evidence": "No examination of whether source corpora are representative or biased toward certain domains or styles."
    },
    {
      "point": "No exploration of incorporating structural or multi-modal code representations.",
      "evidence": "The approach relies solely on token-level similarity without considering ASTs or control/data flow graphs."
    },
    {
      "point": "No user study or practical deployment evaluation.",
      "evidence": "The practical usability and limitations in real software modernization scenarios are not evaluated."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed method compare empirically to recent unsupervised or hybrid code translation approaches?",
      "motivation": "Understanding relative performance and novelty is critical to position the contribution within the field."
    },
    {
      "question": "What is the impact of different similarity threshold values and selection strategies on dataset quality and downstream model performance?",
      "motivation": "A principled approach to threshold selection could improve dataset reliability and model effectiveness."
    },
    {
      "question": "How do different types of noise (semantic vs. syntactic) affect model learning and translation quality?",
      "motivation": "Characterizing noise impact can guide better dataset construction and model robustness."
    },
    {
      "question": "Can incorporating structural code representations improve the quality of noisy parallel datasets beyond token-level similarity?",
      "motivation": "Structural information may reduce noise and enhance pairing accuracy, improving translation results."
    },
    {
      "question": "What are the computational costs and scalability considerations for applying WMD at large scale, and are there efficient approximations?",
      "motivation": "Practical deployment requires understanding resource demands and potential optimizations."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
